// === Trigger-firing prelude for det_create_entry ===
//
// z3 returned `unknown` because every duplicated forall ensures uses a
// trigger that mentions post1_self_.* or post2_self_.* — the two runs'
// triggers therefore never line up, so z3 never propagates the per-run
// `=~=` accessor equalities into a cross-run comparison.  We re-assert
// every forall ensures explicitly for run-1 and run-2 (sound: each one
// is verbatim what the LHS of the function's ensures already proves),
// which forces z3 to instantiate them and produces the per-key accessor
// equalities the det-equal predicate needs.

// --- procs: address-space and proc record agree with pre on all of proc_dom ---
assert(forall|p_ptr: ProcPtr|
    #![auto]
    post1_self_.proc_dom().contains(p_ptr) ==>
        post1_self_.get_address_space(p_ptr) =~= pre_self_.get_address_space(p_ptr)
        && post1_self_.get_proc(p_ptr) =~= pre_self_.get_proc(p_ptr));
assert(forall|p_ptr: ProcPtr|
    #![auto]
    post2_self_.proc_dom().contains(p_ptr) ==>
        post2_self_.get_address_space(p_ptr) =~= pre_self_.get_address_space(p_ptr)
        && post2_self_.get_proc(p_ptr) =~= pre_self_.get_proc(p_ptr));

// --- threads ---
assert(forall|t_ptr: ThreadPtr|
    #![auto]
    post1_self_.thread_dom().contains(t_ptr) ==>
        post1_self_.get_thread(t_ptr) =~= pre_self_.get_thread(t_ptr));
assert(forall|t_ptr: ThreadPtr|
    #![auto]
    post2_self_.thread_dom().contains(t_ptr) ==>
        post2_self_.get_thread(t_ptr) =~= pre_self_.get_thread(t_ptr));

// --- containers (other than the owning_container of proc_ptr) ---
assert(forall|c_ptr: ContainerPtr|
    #![auto]
    post1_self_.container_dom().contains(c_ptr)
        && c_ptr != post1_self_.get_proc(proc_ptr).owning_container ==>
        post1_self_.get_container(c_ptr) =~= pre_self_.get_container(c_ptr));
assert(forall|c_ptr: ContainerPtr|
    #![auto]
    post2_self_.container_dom().contains(c_ptr)
        && c_ptr != post2_self_.get_proc(proc_ptr).owning_container ==>
        post2_self_.get_container(c_ptr) =~= pre_self_.get_container(c_ptr));

// --- endpoints ---
assert(forall|e_ptr: EndpointPtr|
    #![auto]
    post1_self_.endpoint_dom().contains(e_ptr) ==>
        post1_self_.get_endpoint(e_ptr) =~= pre_self_.get_endpoint(e_ptr));
assert(forall|e_ptr: EndpointPtr|
    #![auto]
    post2_self_.endpoint_dom().contains(e_ptr) ==>
        post2_self_.get_endpoint(e_ptr) =~= pre_self_.get_endpoint(e_ptr));

// --- per-container owned pages ---
assert(forall|c_ptr: ContainerPtr|
    #![auto]
    post1_self_.container_dom().contains(c_ptr) ==>
        post1_self_.get_container_owned_pages(c_ptr)
            =~= pre_self_.get_container_owned_pages(c_ptr));
assert(forall|c_ptr: ContainerPtr|
    #![auto]
    post2_self_.container_dom().contains(c_ptr) ==>
        post2_self_.get_container_owned_pages(c_ptr)
            =~= pre_self_.get_container_owned_pages(c_ptr));

// --- page_alloc.page_is_mapped is preserved by each run ---
assert(forall|p: PagePtr|
    #![trigger post1_self_.page_alloc.page_is_mapped(p)]
    post1_self_.page_alloc.page_is_mapped(p) == pre_self_.page_alloc.page_is_mapped(p));
assert(forall|p: PagePtr|
    #![trigger post2_self_.page_alloc.page_is_mapped(p)]
    post2_self_.page_alloc.page_is_mapped(p) == pre_self_.page_alloc.page_is_mapped(p));

// --- mem_man.pcid_to_proc_ptr preserved on active pcids ---
assert(forall|p: Pcid|
    #![trigger post1_self_.mem_man.pcid_active(p)]
    #![trigger post1_self_.mem_man.pcid_to_proc_ptr(p)]
    post1_self_.mem_man.pcid_active(p) ==>
        pre_self_.mem_man.pcid_to_proc_ptr(p) == post1_self_.mem_man.pcid_to_proc_ptr(p));
assert(forall|p: Pcid|
    #![trigger post2_self_.mem_man.pcid_active(p)]
    #![trigger post2_self_.mem_man.pcid_to_proc_ptr(p)]
    post2_self_.mem_man.pcid_active(p) ==>
        pre_self_.mem_man.pcid_to_proc_ptr(p) == post2_self_.mem_man.pcid_to_proc_ptr(p));

// --- page_mapping is invariant for each run; cross-run equality is then trivial ---
assert(post1_self_.page_mapping == pre_self_.page_mapping);
assert(post2_self_.page_mapping == pre_self_.page_mapping);
assert(post1_self_.page_mapping == post2_self_.page_mapping);
assert((post1_self_.page_mapping)@ =~= (post2_self_.page_mapping)@);

// --- domains agree across the two runs (transitivity through pre) ---
assert(post1_self_.proc_dom() =~= post2_self_.proc_dom());
assert(post1_self_.thread_dom() =~= post2_self_.thread_dom());
assert(post1_self_.endpoint_dom() =~= post2_self_.endpoint_dom());
assert(post1_self_.container_dom() =~= post2_self_.container_dom());
